190: class RequestEncoderImpl : public StreamEncoderImpl, public RequestEncoder {
191: public:
192:   RequestEncoderImpl(ConnectionImpl& connection, StreamInfo::BytesMeterSharedPtr&& bytes_meter)
193:       : StreamEncoderImpl(connection, std::move(bytes_meter)) {}
194:   bool upgradeRequest() const { return upgrade_request_; }
195:   bool headRequest() const { return head_request_; }
196:   bool connectRequest() const { return connect_request_; }
197: 
198:   // Http::RequestEncoder
199:   Status encodeHeaders(const RequestHeaderMap& headers, bool end_stream) override;
200:   void encodeTrailers(const RequestTrailerMap& trailers) override { encodeTrailersBase(trailers); }
201:   void enableTcpTunneling() override { is_tcp_tunneling_ = true; }
