331: Status ServerConnectionImpl::doFloodProtectionChecks() const {
332:   ASSERT(dispatching_);
333:   // Before processing another request, make sure that we are below the response flood protection
334:   // threshold.
335:   if (outbound_responses_ >= kMaxOutboundResponses) {
336:     ENVOY_CONN_LOG(trace, "error accepting request: too many pending responses queued",
337:                    connection_);
338:     stats_.response_flood_.inc();
339:     return bufferFloodError("Too many responses queued.");
340:   }
341:   return okStatus();
342: }
