344: uint64_t ConnectionImpl::flushOutput(bool end_encode) {
345:   if (end_encode) {
346:     // If this is an HTTP response in ServerConnectionImpl, track outbound responses for flood
347:     // protection
348:     maybeAddSentinelBufferFragment(*output_buffer_);
349:   }
350:   const uint64_t bytes_encoded = output_buffer_->length();
351:   connection().write(*output_buffer_, false);
352:   ASSERT(0UL == output_buffer_->length());
353:   return bytes_encoded;
354: }
