1234:     // encoding because end stream with zero body length has not yet been indicated.
1235:     if (parser_->isChunked() ||
1236:         (parser_->contentLength().has_value() && parser_->contentLength().value() > 0) ||
1237:         handling_upgrade_) {
1238:       active_request_->request_decoder_->decodeHeaders(std::move(headers), false);
1239: 
1240:       // If the connection has been closed (or is closing) after decoding headers, pause the parser
1241:       // so we return control to the caller.
1242:       if (connection_.state() != Network::Connection::State::Open) {
1243:         return parser_->pause();
1244:       }
1245:     } else {
1246:       deferred_end_stream_headers_ = true;
1247:     }
1248:   }
1249: 
1250:   return CallbackResult::Success;
1251: }
