1312: CallbackResult ServerConnectionImpl::onMessageCompleteBase() {
1313:   ASSERT(!handling_upgrade_);
1314:   if (active_request_) {
1315: 
1316:     // The request_decoder should be non-null after we've called the newStream on callbacks.
1317:     ASSERT(active_request_->request_decoder_);
1318:     active_request_->remote_complete_ = true;
1319: 
1320:     if (deferred_end_stream_headers_) {
1321:       active_request_->request_decoder_->decodeHeaders(
1322:           std::move(absl::get<RequestHeaderMapPtr>(headers_or_trailers_)), true);
1323:       deferred_end_stream_headers_ = false;
1324:     } else if (processing_trailers_) {
1325:       active_request_->request_decoder_->decodeTrailers(
1326:           std::move(absl::get<RequestTrailerMapPtr>(headers_or_trailers_)));
1327:     } else {
1328:       Buffer::OwnedImpl buffer;
1329:       active_request_->request_decoder_->decodeData(buffer, true);
1330:     }
1331: 
1332:     // Reset to ensure no information from one requests persists to the next.
1333:     headers_or_trailers_.emplace<RequestHeaderMapPtr>(nullptr);
1334:   }
1335: 
1336:   // Always pause the parser so that the calling code can process 1 request at a time and apply
1337:   // back pressure. However this means that the calling code needs to detect if there is more data
1338:   // in the buffer and dispatch it again.
1339:   return parser_->pause();
1340: }
