48: /**
49:  * Implementation of Http::HeaderMap. This is heavily optimized for performance. Roughly, when
50:  * headers are added to the map by string, we do a trie lookup to see if it's one of the O(1)
51:  * headers. If it is, we store a reference to it that can be accessed later directly via direct
52:  * method access. Most high performance paths use O(1) direct method access. In general, we try to
53:  * copy as little as possible and allocate as little as possible in any of the paths.
54:  */
55: class HeaderMapImpl : NonCopyable {
56: public:
57:   HeaderMapImpl(const uint32_t max_headers_kb = UINT32_MAX,
58:                 const uint32_t max_headers_count = UINT32_MAX)
59:       : max_headers_kb_(max_headers_kb), max_headers_count_(max_headers_count) {}
60:   virtual ~HeaderMapImpl() = default;
61: 
62:   // The following "constructors" call virtual functions during construction and must use the
63:   // static factory pattern.
64:   static void copyFrom(HeaderMap& lhs, const HeaderMap& rhs);
65:   // The value_type of iterator must be pair, and the first value of them must be LowerCaseString.
66:   // If not, it won't be compiled successfully.
67:   template <class It> static void initFromInitList(HeaderMap& new_header_map, It begin, It end) {
68:     for (auto it = begin; it != end; ++it) {
69:       static_assert(std::is_same<decltype(it->first), LowerCaseString>::value,
70:                     "iterator must be pair and the first value of them must be LowerCaseString");
71:       HeaderString key_string;
72:       key_string.setCopy(it->first.get().c_str(), it->first.get().size());
73:       HeaderString value_string;
74:       value_string.setCopy(it->second.c_str(), it->second.size());
75:       new_header_map.addViaMove(std::move(key_string), std::move(value_string));
76:     }
77:   }
