57: bool HeaderMapImpl::HeaderList::maybeMakeMap() {
58:   if (lazy_map_.empty()) {
59:     if (headers_.size() < kMinHeadersForLazyMap) {
60:       return false;
61:     }
62:     // Add all entries from the list into the map.
63:     for (auto node = headers_.begin(); node != headers_.end(); ++node) {
64:       HeaderNodeVector& v = lazy_map_[node->key().getStringView()];
65:       v.push_back(node);
66:     }
67:   }
68:   return true;
69: }
