71: size_t HeaderMapImpl::HeaderList::remove(absl::string_view key) {
72:   size_t removed_bytes = 0;
73:   if (maybeMakeMap()) {
74:     auto iter = lazy_map_.find(key);
75:     if (iter != lazy_map_.end()) {
76:       // Erase from the map, and all same key entries from the list.
77:       HeaderNodeVector header_nodes = std::move(iter->second);
78:       lazy_map_.erase(iter);
79:       for (const HeaderNode& node : header_nodes) {
80:         ASSERT(node->key() == key);
81:         removed_bytes += node->key().size() + node->value().size();
82:         erase(node, false /* remove_from_map */);
83:       }
84:     }
85:   } else {
86:     // Erase all same key entries from the list.
87:     for (auto i = headers_.begin(); i != headers_.end();) {
88:       if (i->key() == key) {
89:         removed_bytes += i->key().size() + i->value().size();
90:         i = erase(i, false /* remove_from_map */);
91:       } else {
92:         ++i;
93:       }
94:     }
95:   }
96:   return removed_bytes;
97: }
